+function extractInputText(content: unknown[]): string {
+  return content
+    .filter(
+      (entry): entry is { type: "input_text"; text: string } =>
+        !!entry &&
+        typeof entry === "object" &&
+        (entry as { type?: unknown }).type === "input_text" &&
+        typeof (entry as { text?: unknown }).text === "string",
+    )
+    .map((entry) => entry.text)
+    .join("\n")
+    .trim();
